--
-- Name: trg_audit(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."trg_audit"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
    v_user_id INT;
    v_pk      TEXT;
BEGIN
    BEGIN
        v_user_id := current_setting('app.user_id', TRUE)::INT;
    EXCEPTION WHEN OTHERS THEN
        v_user_id := NULL;
    END;
 
    IF TG_TABLE_NAME = 'metric_result' THEN
        v_pk := COALESCE(NEW.result_id::TEXT, OLD.result_id::TEXT);
    ELSIF TG_TABLE_NAME = 'metric_target' THEN
        v_pk := CONCAT_WS(':',
            COALESCE(NEW.plant_id::TEXT,  OLD.plant_id::TEXT),
            COALESCE(NEW.metric_id::TEXT, OLD.metric_id::TEXT),
            COALESCE(NEW.period_id::TEXT, OLD.period_id::TEXT));
    ELSIF TG_TABLE_NAME = 'metric' THEN
        v_pk := COALESCE(NEW.metric_id::TEXT, OLD.metric_id::TEXT);
    ELSIF TG_TABLE_NAME = 'metric_validity' THEN
        v_pk := CONCAT_WS(':',
            COALESCE(NEW.metric_id::TEXT, OLD.metric_id::TEXT),
            COALESCE(NEW.plant_id::TEXT,  OLD.plant_id::TEXT),
            COALESCE(NEW.year::TEXT,      OLD.year::TEXT));
    ELSIF TG_TABLE_NAME = 'app_user' THEN
        v_pk := COALESCE(NEW.user_id::TEXT, OLD.user_id::TEXT);
    ELSIF TG_TABLE_NAME = 'user_plant_area_access' THEN
        v_pk := CONCAT_WS(':',
            COALESCE(NEW.user_id::TEXT,  OLD.user_id::TEXT),
            COALESCE(NEW.plant_id::TEXT, OLD.plant_id::TEXT),
            COALESCE(NEW.area_id::TEXT,  OLD.area_id::TEXT));
    ELSIF TG_TABLE_NAME = 'scorecard_threshold' THEN
        v_pk := COALESCE(NEW.threshold_id::TEXT, OLD.threshold_id::TEXT);
    ELSE
        v_pk := '?';
    END IF;
 
    IF TG_OP = 'INSERT' THEN
        VALUES (TG_TABLE_NAME, v_pk, 'INSERT', to_jsonb(NEW), v_user_id);
        RETURN NEW;
    ELSIF TG_OP = 'UPDATE' THEN
        VALUES (TG_TABLE_NAME, v_pk, 'UPDATE', to_jsonb(OLD), to_jsonb(NEW), v_user_id);
        RETURN NEW;
    ELSIF TG_OP = 'DELETE' THEN
        VALUES (TG_TABLE_NAME, v_pk, 'DELETE', to_jsonb(OLD), v_user_id);
        RETURN OLD;
    END IF;
    RETURN NULL;
END;
$$;


