--
-- Name: metric_result; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE "public"."metric_result" (
    "result_id" bigint NOT NULL,
    "plant_id" integer NOT NULL,
    "metric_id" integer NOT NULL,
    "period_id" integer NOT NULL,
    "result_value" numeric(14,4),
    "comment" "text",
    "issue" "text",
    "corrective_action" "text",
    "target_date" "date",
    "owner_user_id" integer,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "created_by" integer,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_by" integer,
    "owner_text" character varying(200),
    "is_resolved" boolean DEFAULT false NOT NULL,
    "resolution_note" "text",
    "resolved_at" timestamp with time zone,
    "resolved_by" integer,
    CONSTRAINT "chk_resolution_consistency" CHECK (((("is_resolved" = false) AND ("resolution_note" IS NULL) AND ("resolved_at" IS NULL) AND ("resolved_by" IS NULL)) OR (("is_resolved" = true) AND ("resolution_note" IS NOT NULL) AND ("length"(TRIM(BOTH FROM "resolution_note")) > 0) AND ("resolved_at" IS NOT NULL) AND ("resolved_by" IS NOT NULL))))
);


