--
-- Name: v_metric_score; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_metric_score" AS
 SELECT "r"."result_id",
    "r"."plant_id",
    "r"."period_id",
    "r"."metric_id",
    "m"."area_id",
    "m"."process_id",
    "r"."result_value",
    "t"."yellow_limit",
    "t"."green_limit",
    "m"."higher_is_better",
        CASE
            WHEN (("r"."result_value" IS NULL) OR ("t"."green_limit" IS NULL)) THEN NULL::integer
            WHEN "m"."higher_is_better" THEN
            CASE
                WHEN ("r"."result_value" >= "t"."green_limit") THEN 2
                WHEN ("r"."result_value" >= "t"."yellow_limit") THEN 1
                ELSE 0
            END
            ELSE
            CASE
                WHEN ("r"."result_value" <= "t"."green_limit") THEN 2
                WHEN ("r"."result_value" <= "t"."yellow_limit") THEN 1
                ELSE 0
            END
        END AS "score"
   FROM (("public"."metric_result" "r"
     JOIN "public"."metric" "m" ON (("m"."metric_id" = "r"."metric_id")))
     LEFT JOIN "public"."metric_target" "t" ON ((("t"."plant_id" = "r"."plant_id") AND ("t"."metric_id" = "r"."metric_id") AND ("t"."period_id" = "r"."period_id"))));


--
-- Name: VIEW "v_metric_score"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW "public"."v_metric_score" IS 'Each metric scored 0 (red), 1 (yellow), or 2 (green) based on its target and direction.';


--
-- Name: v_scorecard_cell; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_scorecard_cell" AS
 WITH "cell" AS (
         SELECT "v_metric_score"."plant_id",
            "v_metric_score"."period_id",
            "v_metric_score"."area_id",
            "v_metric_score"."process_id",
            "count"("v_metric_score"."score") AS "metrics_count",
            "sum"("v_metric_score"."score") AS "total_score"
           FROM "public"."v_metric_score"
          WHERE ("v_metric_score"."score" IS NOT NULL)
          GROUP BY "v_metric_score"."plant_id", "v_metric_score"."period_id", "v_metric_score"."area_id", "v_metric_score"."process_id"
        ), "threshold" AS (
         SELECT "scorecard_threshold"."yellow_min",
            "scorecard_threshold"."green_min"
           FROM "public"."scorecard_threshold"
          WHERE ("scorecard_threshold"."effective_from" <= CURRENT_DATE)
          ORDER BY "scorecard_threshold"."effective_from" DESC
         LIMIT 1
        )
 SELECT "c"."plant_id",
    "c"."period_id",
    "c"."area_id",
    "c"."process_id",
    "c"."metrics_count",
    "c"."total_score",
    (("c"."total_score")::numeric / ((2 * "c"."metrics_count"))::numeric) AS "compliance_ratio",
        CASE
            WHEN ((("c"."total_score")::numeric / ((2 * "c"."metrics_count"))::numeric) >= "t"."green_min") THEN 'green'::"text"
            WHEN ((("c"."total_score")::numeric / ((2 * "c"."metrics_count"))::numeric) >= "t"."yellow_min") THEN 'yellow'::"text"
            ELSE 'red'::"text"
        END AS "color"
   FROM ("cell" "c"
     CROSS JOIN "threshold" "t");


--
-- Name: VIEW "v_scorecard_cell"; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON VIEW "public"."v_scorecard_cell" IS 'Compliance ratio and color per (plant, period, area, process). Replaces legacy T_Graph.';


--
-- Name: v_scorecard_area_total; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_scorecard_area_total" AS
 WITH "agg" AS (
         SELECT "v_scorecard_cell"."plant_id",
            "v_scorecard_cell"."period_id",
            "v_scorecard_cell"."area_id",
            "sum"("v_scorecard_cell"."total_score") AS "total_score",
            "sum"("v_scorecard_cell"."metrics_count") AS "metrics_count"
           FROM "public"."v_scorecard_cell"
          GROUP BY "v_scorecard_cell"."plant_id", "v_scorecard_cell"."period_id", "v_scorecard_cell"."area_id"
        ), "threshold" AS (
         SELECT "scorecard_threshold"."yellow_min",
            "scorecard_threshold"."green_min"
           FROM "public"."scorecard_threshold"
          WHERE ("scorecard_threshold"."effective_from" <= CURRENT_DATE)
          ORDER BY "scorecard_threshold"."effective_from" DESC
         LIMIT 1
        )
 SELECT "a"."plant_id",
    "a"."period_id",
    "a"."area_id",
    "a"."metrics_count",
    "a"."total_score",
    ("a"."total_score" / ((2)::numeric * "a"."metrics_count")) AS "compliance_ratio",
        CASE
            WHEN (("a"."total_score" / ((2)::numeric * "a"."metrics_count")) >= "t"."green_min") THEN 'green'::"text"
            WHEN (("a"."total_score" / ((2)::numeric * "a"."metrics_count")) >= "t"."yellow_min") THEN 'yellow'::"text"
            ELSE 'red'::"text"
        END AS "color"
   FROM ("agg" "a"
     CROSS JOIN "threshold" "t");


