--
-- Name: v_metric_history; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_metric_history" AS
 SELECT "r"."plant_id",
    "r"."metric_id",
    "pe"."period_id",
    "pe"."year",
    "pe"."month",
    "pe"."period_date",
    "r"."result_value",
    "t"."yellow_limit",
    "t"."green_limit",
    "m"."higher_is_better"
   FROM ((("public"."metric_result" "r"
     JOIN "public"."metric" "m" ON (("m"."metric_id" = "r"."metric_id")))
     JOIN "public"."period" "pe" ON (("pe"."period_id" = "r"."period_id")))
     LEFT JOIN "public"."metric_target" "t" ON ((("t"."plant_id" = "r"."plant_id") AND ("t"."metric_id" = "r"."metric_id") AND ("t"."period_id" = "r"."period_id"))));


--
-- Name: v_metric_yearly; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_metric_yearly" AS
 SELECT "mr"."plant_id",
    (EXTRACT(year FROM "p"."period_date"))::integer AS "year",
    "mr"."metric_id",
    "m"."area_id",
    "m"."process_id",
    "m"."name",
    "m"."unit",
    "m"."higher_is_better",
    "avg"("mr"."result_value") AS "aggregated_value",
    "max"("mt"."yellow_limit") AS "yellow_limit",
    "max"("mt"."green_limit") AS "green_limit",
        CASE
            WHEN "m"."higher_is_better" THEN
            CASE
                WHEN ("avg"("mr"."result_value") >= "max"("mt"."green_limit")) THEN 'green'::"text"
                WHEN ("avg"("mr"."result_value") >= "max"("mt"."yellow_limit")) THEN 'yellow'::"text"
                ELSE 'red'::"text"
            END
            ELSE
            CASE
                WHEN ("avg"("mr"."result_value") <= "max"("mt"."green_limit")) THEN 'green'::"text"
                WHEN ("avg"("mr"."result_value") <= "max"("mt"."yellow_limit")) THEN 'yellow'::"text"
                ELSE 'red'::"text"
            END
        END AS "color"
   FROM ((("public"."metric_result" "mr"
     JOIN "public"."metric" "m" ON (("m"."metric_id" = "mr"."metric_id")))
     JOIN "public"."period" "p" ON (("p"."period_id" = "mr"."period_id")))
     JOIN "public"."metric_target" "mt" ON ((("mt"."plant_id" = "mr"."plant_id") AND ("mt"."metric_id" = "mr"."metric_id") AND ("mt"."period_id" = "mr"."period_id"))))
  WHERE ("mr"."result_value" IS NOT NULL)
  GROUP BY "mr"."plant_id", ((EXTRACT(year FROM "p"."period_date"))::integer), "mr"."metric_id", "m"."area_id", "m"."process_id", "m"."name", "m"."unit", "m"."higher_is_better";


--
-- Name: v_scorecard_process_total; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_scorecard_process_total" AS
 WITH "agg" AS (
         SELECT "v_scorecard_cell"."plant_id",
            "v_scorecard_cell"."period_id",
            "v_scorecard_cell"."process_id",
            "sum"("v_scorecard_cell"."total_score") AS "total_score",
            "sum"("v_scorecard_cell"."metrics_count") AS "metrics_count"
           FROM "public"."v_scorecard_cell"
          GROUP BY "v_scorecard_cell"."plant_id", "v_scorecard_cell"."period_id", "v_scorecard_cell"."process_id"
        ), "threshold" AS (
         SELECT "scorecard_threshold"."yellow_min",
            "scorecard_threshold"."green_min"
           FROM "public"."scorecard_threshold"
          WHERE ("scorecard_threshold"."effective_from" <= CURRENT_DATE)
          ORDER BY "scorecard_threshold"."effective_from" DESC
         LIMIT 1
        )
 SELECT "a"."plant_id",
    "a"."period_id",
    "a"."process_id",
    "a"."metrics_count",
    "a"."total_score",
    ("a"."total_score" / ((2)::numeric * "a"."metrics_count")) AS "compliance_ratio",
        CASE
            WHEN (("a"."total_score" / ((2)::numeric * "a"."metrics_count")) >= "t"."green_min") THEN 'green'::"text"
            WHEN (("a"."total_score" / ((2)::numeric * "a"."metrics_count")) >= "t"."yellow_min") THEN 'yellow'::"text"
            ELSE 'red'::"text"
        END AS "color"
   FROM ("agg" "a"
     CROSS JOIN "threshold" "t");


