--
-- Name: v_scorecard_cell_yearly; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_scorecard_cell_yearly" AS
 SELECT "mr"."plant_id",
    (EXTRACT(year FROM "p"."period_date"))::integer AS "year",
    "m"."area_id",
    "m"."process_id",
    "count"("mr"."metric_id") AS "metrics_count",
    "sum"(
        CASE
            WHEN "m"."higher_is_better" THEN
            CASE
                WHEN ("mr"."result_value" >= "mt"."green_limit") THEN 2
                WHEN ("mr"."result_value" >= "mt"."yellow_limit") THEN 1
                ELSE 0
            END
            ELSE
            CASE
                WHEN ("mr"."result_value" <= "mt"."green_limit") THEN 2
                WHEN ("mr"."result_value" <= "mt"."yellow_limit") THEN 1
                ELSE 0
            END
        END) AS "total_score",
    "round"((("sum"(
        CASE
            WHEN "m"."higher_is_better" THEN
            CASE
                WHEN ("mr"."result_value" >= "mt"."green_limit") THEN 2
                WHEN ("mr"."result_value" >= "mt"."yellow_limit") THEN 1
                ELSE 0
            END
            ELSE
            CASE
                WHEN ("mr"."result_value" <= "mt"."green_limit") THEN 2
                WHEN ("mr"."result_value" <= "mt"."yellow_limit") THEN 1
                ELSE 0
            END
        END))::numeric / (NULLIF((2 * "count"("mr"."metric_id")), 0))::numeric), 4) AS "compliance_ratio",
        CASE
            WHEN ("round"((("sum"(
            CASE
                WHEN "m"."higher_is_better" THEN
                CASE
                    WHEN ("mr"."result_value" >= "mt"."green_limit") THEN 2
                    WHEN ("mr"."result_value" >= "mt"."yellow_limit") THEN 1
                    ELSE 0
                END
                ELSE
                CASE
                    WHEN ("mr"."result_value" <= "mt"."green_limit") THEN 2
                    WHEN ("mr"."result_value" <= "mt"."yellow_limit") THEN 1
                    ELSE 0
                END
            END))::numeric / (NULLIF((2 * "count"("mr"."metric_id")), 0))::numeric), 4) >= ( SELECT "scorecard_threshold"."green_min"
               FROM "public"."scorecard_threshold"
              WHERE ("scorecard_threshold"."effective_from" <= CURRENT_DATE)
              ORDER BY "scorecard_threshold"."effective_from" DESC
             LIMIT 1)) THEN 'green'::"text"
            WHEN ("round"((("sum"(
            CASE
                WHEN "m"."higher_is_better" THEN
                CASE
                    WHEN ("mr"."result_value" >= "mt"."green_limit") THEN 2
                    WHEN ("mr"."result_value" >= "mt"."yellow_limit") THEN 1
                    ELSE 0
                END
                ELSE
                CASE
                    WHEN ("mr"."result_value" <= "mt"."green_limit") THEN 2
                    WHEN ("mr"."result_value" <= "mt"."yellow_limit") THEN 1
                    ELSE 0
                END
            END))::numeric / (NULLIF((2 * "count"("mr"."metric_id")), 0))::numeric), 4) >= ( SELECT "scorecard_threshold"."yellow_min"
               FROM "public"."scorecard_threshold"
              WHERE ("scorecard_threshold"."effective_from" <= CURRENT_DATE)
              ORDER BY "scorecard_threshold"."effective_from" DESC
             LIMIT 1)) THEN 'yellow'::"text"
            ELSE 'red'::"text"
        END AS "color"
   FROM ((("public"."metric_result" "mr"
     JOIN "public"."metric" "m" ON (("m"."metric_id" = "mr"."metric_id")))
     JOIN "public"."period" "p" ON (("p"."period_id" = "mr"."period_id")))
     JOIN "public"."metric_target" "mt" ON ((("mt"."plant_id" = "mr"."plant_id") AND ("mt"."metric_id" = "mr"."metric_id") AND ("mt"."period_id" = "mr"."period_id"))))
  WHERE ("mr"."result_value" IS NOT NULL)
  GROUP BY "mr"."plant_id", ((EXTRACT(year FROM "p"."period_date"))::integer), "m"."area_id", "m"."process_id";


--
-- Name: v_scorecard_area_total_yearly; Type: VIEW; Schema: public; Owner: -
