    "sum"("total_score") AS "total_score",
    "round"(("sum"("total_score") / NULLIF(((2)::numeric * "sum"("metrics_count")), (0)::numeric)), 4) AS "compliance_ratio",
        CASE
            WHEN ("round"(("sum"("total_score") / NULLIF(((2)::numeric * "sum"("metrics_count")), (0)::numeric)), 4) >= ( SELECT "scorecard_threshold"."green_min"
               FROM "public"."scorecard_threshold"
              WHERE ("scorecard_threshold"."effective_from" <= CURRENT_DATE)
              ORDER BY "scorecard_threshold"."effective_from" DESC
             LIMIT 1)) THEN 'green'::"text"
            WHEN ("round"(("sum"("total_score") / NULLIF(((2)::numeric * "sum"("metrics_count")), (0)::numeric)), 4) >= ( SELECT "scorecard_threshold"."yellow_min"
               FROM "public"."scorecard_threshold"
              WHERE ("scorecard_threshold"."effective_from" <= CURRENT_DATE)
              ORDER BY "scorecard_threshold"."effective_from" DESC
             LIMIT 1)) THEN 'yellow'::"text"
            ELSE 'red'::"text"
        END AS "color"
   FROM "public"."v_scorecard_cell_yearly"
  GROUP BY "plant_id", "year", "area_id";


